#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "basic-block.h"
#include "cfghooks.h"
#include "dumpfile.h"

/* Main routine to count basic blocks per function.  */

static unsigned int
count_basic_blocks_per_function ()
{
  basic_block bb;
  int bb_count = 0;

  FOR_EACH_BB_FN (bb, cfun)
    {
      bb_count++;
    }

  if (dump_file && (dump_flags & TDF_DETAILS))
    {
      fprintf (dump_file, "Function %s has %d basic blocks\n",
	       function_name (cfun), bb_count);
    }

  return 0;
}

namespace {

const pass_data pass_data_count_bbs =
{
  GIMPLE_PASS, /* type */
  "count_bbs", /* name */
  OPTGROUP_NONE, /* optinfo_flags */
  TV_TREE_SSA, /* tv_id */
  ( PROP_cfg | PROP_ssa ), /* properties_required */
  0, /* properties_provided */
  0, /* properties_destroyed */
  0, /* todo_flags_start */
  0, /* todo_flags_finish */
};

class pass_count_bbs : public gimple_opt_pass
{
public:
  pass_count_bbs (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_bbs, ctxt)
  {
  }

  /* opt_pass methods: */
  bool gate (function *) final override { return true; }
  unsigned int execute (function *) final override
    {
      return count_basic_blocks_per_function ();
    }

}; // class pass_count_bbs

} // anon namespace

gimple_opt_pass *
make_pass_count_bbs (gcc::context *ctxt)
{
  return new pass_count_bbs (ctxt);
}

